# Builder pattern — construction fluente d'objets complexes
class QueryBuilder {
    hidden [string]$_table
    hidden [string[]]$_columns = @('*')
    hidden [string[]]$_wheres  = @()
    hidden [int]$_limit        = 0

    [QueryBuilder] From([string]$table) {
        $this._table = $table; return $this
    }
    [QueryBuilder] Select([string[]]$cols) {
        $this._columns = $cols; return $this
    }
    [QueryBuilder] Where([string]$condition) {
        $this._wheres += $condition; return $this
    }
    [QueryBuilder] Limit([int]$n) {
        $this._limit = $n; return $this
    }
    [string] Build() {
        $q  = "SELECT $($this._columns -join ', ') FROM $($this._table)"
        if ($this._wheres) { $q += " WHERE $($this._wheres -join ' AND ')" }
        if ($this._limit -gt 0) { $q += " LIMIT $($this._limit)" }
        return $q
    }
}

$query = [QueryBuilder]::new()
    .From('users')
    .Select(@('id','name','email'))
    .Where('active = 1')
    .Where('age > 18')
    .Limit(10)
    .Build()

Write-Host $query
# SELECT id, name, email FROM users WHERE active = 1 AND age > 18 LIMIT 10

# Strategy pattern — algorithmes interchangeables
class Sorter {
    hidden [scriptblock]$_strategy

    Sorter([scriptblock]$strategy) { $this._strategy = $strategy }

    [object[]] Sort([object[]]$data) {
        return $data | Sort-Object -Property $this._strategy
    }
}

$byName   = [Sorter]::new({ $_.Name })
$byLength = [Sorter]::new({ $_.Length })

$files = Get-ChildItem C:\Windows\System32 -File | Select-Object -First 20
$byName.Sort($files)   | Select-Object -First 5 Name
$byLength.Sort($files) | Select-Object -First 5 Name, Length
