# ConfigManager.psm1 — module complet de gestion de configuration

class ConfigStore {
    hidden [hashtable]$_data = @{}
    hidden [string]$_path

    ConfigStore([string]$path) {
        $this._path = $path
        if (Test-Path $path) { $this.Load() }
    }

    [void] Set([string]$key, [object]$value) {
        $this._data[$key] = $value
    }
    [object] Get([string]$key, [object]$default = $null) {
        return $this._data.ContainsKey($key) ? $this._data[$key] : $default
    }
    [void] Load() {
        $this._data = Get-Content $this._path | ConvertFrom-Json -AsHashtable
    }
    [void] Save() {
        $this._data | ConvertTo-Json -Depth 10 | Set-Content $this._path
    }
    [string[]] Keys() { return $this._data.Keys }
}

# API publique du module
function New-ConfigStore {
<#
.SYNOPSIS Crée un nouveau store de configuration JSON.
.PARAMETER Path Chemin du fichier JSON.
#>
    param([Parameter(Mandatory)][string]$Path)
    [ConfigStore]::new($Path)
}

function Get-Config {
    param(
        [Parameter(Mandatory)][ConfigStore]$Store,
        [Parameter(Mandatory)][string]$Key,
        [object]$Default
    )
    $Store.Get($Key, $Default)
}

function Set-Config {
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory)][ConfigStore]$Store,
        [Parameter(Mandatory)][string]$Key,
        [Parameter(Mandatory)][object]$Value
    )
    if ($PSCmdlet.ShouldProcess($Key, "Définir config")) {
        $Store.Set($Key, $Value)
        $Store.Save()
    }
}

# Utilisation
$cfg = New-ConfigStore -Path "$env:TEMP\app.json"
Set-Config -Store $cfg -Key 'debug' -Value $true
Set-Config -Store $cfg -Key 'maxRetries' -Value 3
Write-Host "Debug : $(Get-Config -Store $cfg -Key 'debug')"
Write-Host "Retries : $(Get-Config -Store $cfg -Key 'maxRetries' -Default 1)"
