class UrlBuilder {
    hidden [string]$_scheme = 'https'
    hidden [string]$_host
    hidden [string]$_path = ''
    hidden [System.Collections.Specialized.OrderedDictionary]$_params

    UrlBuilder() { $this._params = [ordered]@{} }

    [UrlBuilder] Scheme([string]$s) { $this._scheme = $s; return $this }
    [UrlBuilder] Host([string]$h)   { $this._host = $h; return $this }
    [UrlBuilder] Path([string]$p)   { $this._path = $p; return $this }
    [UrlBuilder] AddParam([string]$k, [object]$v) {
        $this._params[$k] = $v; return $this
    }
    [string] Build() {
        $url = "$($this._scheme)://$($this._host)$($this._path)"
        if ($this._params.Count -gt 0) {
            $qs = ($this._params.GetEnumerator() | ForEach-Object { "$($_.Key)=$($_.Value)" }) -join '&'
            $url += "?$qs"
        }
        return $url
    }
}

$url = [UrlBuilder]::new()
    .Scheme('https')
    .Host('api.example.com')
    .Path('/users')
    .AddParam('page', 1)
    .AddParam('limit', 50)
    .Build()

Write-Host $url

function Update-Version {
    param(
        [Parameter(Mandatory)]
        [ValidatePattern('^\d+\.\d+\.\d+$')]
        [string]$Version,

        [Parameter(Mandatory)]
        [ValidateSet('Major','Minor','Patch')]
        [string]$BumpType
    )

    $parts = $Version -split '\.' | ForEach-Object { [int]$_ }
    $major, $minor, $patch = $parts[0], $parts[1], $parts[2]

    $new = switch ($BumpType) {
        'Major' { "$($major+1).0.0" }
        'Minor' { "$major.$($minor+1).0" }
        'Patch' { "$major.$minor.$($patch+1)" }
    }

    Write-Host "$Version $BumpType → $new"
    return $new
}

Update-Version -Version '1.2.3' -BumpType 'Patch'
Update-Version -Version '1.2.3' -BumpType 'Minor'
Update-Version -Version '1.2.3' -BumpType 'Major'
